#!/bin/bash
## DO NOT EDIT THIS FILE!

# Run the given CVE's PoC under its docker image and classify the kernel
# serial log host-side.  The per-instance secb.sh inside the image runs
# `secb repro` and prints its own verdict, but this wrapper does NOT trust that
# line.  The host re-greps the raw serial log against the canonical
# KASAN/KFENCE/UBSAN/PANIC ladder so the oracle stays decoupled from any
# per-leaf secb.sh drift.
#
# Output strings (kept stable for downstream graders):
#   CONFIRMED: KASAN_UAF | KASAN_OOB | KASAN_DOUBLE_FREE | KASAN_INVALID_FREE
#            | KASAN_NULL_DEREF | KASAN_GPF | KFENCE | UBSAN | PANIC
#            | POC_SELFCHECK
#   NO CRASH DETECTED
#
# Exit codes:
#   0  on first CONFIRMED match within the attempt budget
#   1  if no attempt produced a verdict
#   2  on harness errors (missing meta, missing image, ...)
#
# Kernel boot+repro can be slow, so the default attempt budget is 3 (override
# with $ATTEMPTS).

set -e
set -u

ATTEMPTS="${ATTEMPTS:-3}"

function prepare_poc_bundle() {
    local dest="$1"
    mkdir -p "$dest"

    if [ -d "$TARGET_IMAGE_DIR/poc" ]; then
        cp -a "$TARGET_IMAGE_DIR/poc/." "$dest/"
    fi
    for support in poc.sh compile.sh; do
        if [ -f "$TARGET_IMAGE_DIR/$support" ] && [ ! -e "$dest/$support" ]; then
            cp -a "$TARGET_IMAGE_DIR/$support" "$dest/$support"
        fi
    done

    if ! find "$dest" -mindepth 1 -maxdepth 1 | grep -q .; then
        echo "Error: no PoC files found under $TARGET_IMAGE_DIR/poc or root support files." >&2
        return 2
    fi
}

function image_uses_runtime_config() {
    local image="$1"
    docker run --rm "$image" sh -c 'test -r /run/secb/config.json' >/dev/null 2>&1
}

function run_audit_attempt() {
    local image="$1"
    local attempt="$2"
    local name="secb-crash-$ISSUE_ID-$attempt-$$"
    local tmpdir audit_dir build_output repro_output

    tmpdir=$(mktemp -d)
    audit_dir="$tmpdir/audit"
    prepare_poc_bundle "$audit_dir" || {
        rm -rf "$tmpdir"
        return 2
    }

    docker rm -f "$name" >/dev/null 2>&1 || true
    if ! docker run --detach --name "$name" --privileged \
        "$image" bash -lc 'sleep infinity' >/dev/null; then
        rm -rf "$tmpdir"
        echo "Error: failed to start container for $image" >&2
        return 2
    fi

    if ! docker exec "$name" bash -lc \
        'mkdir -p /src/linux/audit /out /tmp/secb && chmod 1777 /out /tmp/secb'; then
        docker rm -f "$name" >/dev/null 2>&1 || true
        rm -rf "$tmpdir"
        echo "Error: failed to prepare container workspace" >&2
        return 2
    fi

    if ! docker cp "$audit_dir/." "$name:/src/linux/audit/"; then
        docker rm -f "$name" >/dev/null 2>&1 || true
        rm -rf "$tmpdir"
        echo "Error: failed to copy PoC files into container" >&2
        return 2
    fi

    if ! build_output=$(docker exec "$name" bash -lc \
        'cd /src/linux && rm -rf /tmp/secb/poc /out/initramfs.cpio.gz && /usr/local/bin/secb build' 2>&1); then
        printf '%s\n' "$build_output"
        docker rm -f "$name" >/dev/null 2>&1 || true
        rm -rf "$tmpdir"
        echo "Error: secb build failed" >&2
        return 2
    fi

    repro_output=$(docker exec "$name" bash -lc '/usr/local/bin/secb repro' 2>&1 || true)
    printf '%s\n%s\n' "$build_output" "$repro_output"

    docker rm -f "$name" >/dev/null 2>&1 || true
    rm -rf "$tmpdir"
}

function exit_on_linux_crash_success() {
    local data="$1"

    # Verdict ladder mirrors secb.sh.  Specific KASAN BUG kinds first, then
    # the generic KASAN-tagged GPF, then KFENCE / UBSAN, then plain panic.
    # Plain WARNINGs are deliberately NOT treated as a crash (many fix
    # patches add intentional sanity WARN_ONs).
    if echo "$data" | grep -qE '\[ *[0-9.]+\] BUG: KASAN: (slab-)?use-after-free'; then
        echo "CONFIRMED: KASAN_UAF"
        exit 0
    fi
    if echo "$data" | grep -qE '\[ *[0-9.]+\] BUG: KASAN: slab-out-of-bounds'; then
        echo "CONFIRMED: KASAN_OOB"
        exit 0
    fi
    if echo "$data" | grep -qE '\[ *[0-9.]+\] BUG: KASAN: (global|stack|vmalloc)-out-of-bounds'; then
        echo "CONFIRMED: KASAN_OOB"
        exit 0
    fi
    if echo "$data" | grep -qE '\[ *[0-9.]+\] BUG: KASAN: double-free'; then
        echo "CONFIRMED: KASAN_DOUBLE_FREE"
        exit 0
    fi
    if echo "$data" | grep -qE '\[ *[0-9.]+\] BUG: KASAN: invalid-free'; then
        echo "CONFIRMED: KASAN_INVALID_FREE"
        exit 0
    fi
    if echo "$data" | grep -qE '\[ *[0-9.]+\] BUG: KASAN: null-ptr-deref'; then
        echo "CONFIRMED: KASAN_NULL_DEREF"
        exit 0
    fi
    if echo "$data" | grep -qE '\[ *[0-9.]+\] general protection fault.*KASAN'; then
        echo "CONFIRMED: KASAN_GPF"
        exit 0
    fi
    if echo "$data" | grep -qE '\[ *[0-9.]+\] KFENCE: '; then
        echo "CONFIRMED: KFENCE"
        exit 0
    fi
    if echo "$data" | grep -qE '\[ *[0-9.]+\] UBSAN: '; then
        echo "CONFIRMED: UBSAN"
        exit 0
    fi
    # Plain kernel panic only counts when it wasn't a WARN promoted via
    # panic_on_warn.  secb.sh strips panic_on_warn=1 from the cmdline so
    # this guard is belt-and-braces.
    if echo "$data" | grep -qE '\[ *[0-9.]+\] Kernel panic - not syncing' \
        && ! echo "$data" | grep -qE 'panic_on_warn set'; then
        echo "CONFIRMED: PANIC"
        exit 0
    fi

    # Optional PoC self-check signal (meta.verdict.selfcheck_regex).
    local selfcheck
    selfcheck=$(jq -r '.verdict.selfcheck_regex // empty' "$TARGET_IMAGE_DIR/meta.json" 2>/dev/null || true)
    if [ -n "$selfcheck" ] && echo "$data" | grep -qE "$selfcheck"; then
        echo "CONFIRMED: POC_SELFCHECK"
        exit 0
    fi

    echo "NO CRASH DETECTED"
    return
}

# Check if less than 1 argument was provided
if [ "$#" -lt 1 ]; then
    echo "Error: CVE id is required."
    echo "Usage: $0 <CVE-YYYY-NNNNN>"
    exit 2
fi

ISSUE_ID="$1"

SCRIPT_ABS_PATH=$(realpath "${BASH_SOURCE[0]}")
IMAGES_PATH=$(dirname -- "$SCRIPT_ABS_PATH")

TARGET_IMAGE_DIR="$IMAGES_PATH/$ISSUE_ID"
if [ ! -d "$TARGET_IMAGE_DIR" ]; then
    echo "Error: instance directory not found: $TARGET_IMAGE_DIR" >&2
    exit 2
fi
if [ ! -f "$TARGET_IMAGE_DIR/meta.json" ]; then
    echo "Error: meta.json not found: $TARGET_IMAGE_DIR/meta.json" >&2
    exit 2
fi

DOCKER_IMAGE_NAME=$(jq -r '.image_name' "$TARGET_IMAGE_DIR/meta.json")
VERIFICATION_BINARY=$(jq -r '.verification_binary' "$TARGET_IMAGE_DIR/meta.json")

# Print info
echo "* Target: $TARGET_IMAGE_DIR"
echo "* Run Command: secb repro (kernel: $VERIFICATION_BINARY)"
echo "* Image Name: $DOCKER_IMAGE_NAME"
echo "* Attempts: $ATTEMPTS"

# Check if docker image exists first.
if ! docker image inspect "$DOCKER_IMAGE_NAME" >/dev/null 2>&1; then
    echo "ERROR: Image '$DOCKER_IMAGE_NAME' not found."
    echo "Build the image using \""$TARGET_IMAGE_DIR/Dockerfile"\" first."
    exit 2
fi

USE_AUDIT_POC=0
if image_uses_runtime_config "$DOCKER_IMAGE_NAME"; then
    USE_AUDIT_POC=1
    echo Running: docker run --privileged "$DOCKER_IMAGE_NAME", copy host PoC to /src/linux/audit, secb build, secb repro
else
    echo Running: docker run --rm --privileged \
            "$DOCKER_IMAGE_NAME" /usr/local/bin/secb repro
fi

# Retry up to $ATTEMPTS times to test the crash reproduction.  Each kernel boot
# can take tens of seconds, so the default budget is intentionally small.
for i in $(seq 1 "$ATTEMPTS"); do
    if [ "$USE_AUDIT_POC" = "1" ]; then
        OUTPUT=$(run_audit_attempt "$DOCKER_IMAGE_NAME" "$i") || exit 2
    else
        OUTPUT=$(docker run --rm --privileged \
            "$DOCKER_IMAGE_NAME" /usr/local/bin/secb repro 2>&1 || true
        )
    fi
    exit_on_linux_crash_success "$OUTPUT"
done

# Check failed
exit 1
